Here's the standard approach:

### 1. Define each theme as a `ResourceDictionary`

```xml
<!-- Resources/Styles/LightTheme.xaml -->
<ResourceDictionary xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
                    xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml">
    <Color x:Key="PageBackground">#FFFFFF</Color>
    <Color x:Key="PrimaryText">#1A1A1A</Color>
    <Color x:Key="Accent">#0078D4</Color>
</ResourceDictionary>
```

```xml
<!-- DarkTheme.xaml / HighContrastTheme.xaml — same keys, different values -->
```

Use **identical keys** in every theme so bindings resolve regardless of which dictionary is active.

### 2. Create a theme service

```csharp
public static class ThemeService
{
    public static void ApplyTheme(string themeName)
    {
        var mergedDicts = Application.Current!.Resources.MergedDictionaries;

        // Remove the current theme dictionary (always the last one added)
        if (mergedDicts.LastOrDefault() is ResourceDictionary old)
            mergedDicts.Remove(old);

        ResourceDictionary theme = themeName switch
        {
            "Dark"         => new Resources.Styles.DarkTheme(),
            "HighContrast"  => new Resources.Styles.HighContrastTheme(),
            _              => new Resources.Styles.LightTheme(),
        };

        mergedDicts.Add(theme);

        // Persist the choice
        Preferences.Set("AppTheme", themeName);
    }
}
```

### 3. Load the saved theme at startup

In `App.xaml.cs`:

```csharp
public App()
{
    InitializeComponent();
    ThemeService.ApplyTheme(Preferences.Get("AppTheme", "Light"));
}
```

### 4. Wire up the settings page

```xml
<Picker Title="Theme" SelectedIndexChanged="OnThemeChanged">
    <Picker.Items>
        <x:String>Light</x:String>
        <x:String>Dark</x:String>
        <x:String>HighContrast</x:String>
    </Picker.Items>
</Picker>
```

```csharp
void OnThemeChanged(object sender, EventArgs e)
{
    if (sender is Picker p && p.SelectedItem is string theme)
        ThemeService.ApplyTheme(theme);
}
```

### 5. Consume theme colors with `DynamicResource`

```xml
<ContentPage BackgroundColor="{DynamicResource PageBackground}">
    <Label TextColor="{DynamicResource PrimaryText}" Text="Hello" />
</ContentPage>
```

> **Key point:** Use `DynamicResource` (not `StaticResource`) so controls pick up the new values immediately when the dictionary is swapped at runtime.
